def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def sum_of_divisors_of_p3(p):
    return 1 + p + p**2 + p**3

def sum_of_divisors_of_pq(p, q):
    return 1 + p + q + p * q

def is_nice(n):
    # Check if n can be written as 1 + p + p^2 + p^3 for some prime p
    for p in range(2, int(n**(1/3)) + 1):
        if is_prime(p) and sum_of_divisors_of_p3(p) == n:
            return True
    # Check if n can be written as 1 + p + q + pq for some distinct primes p and q
