            for q in range(p + 1, int(n**0.5) + 1):
                if is_prime(q) and sum_of_divisors_of_pq(p, q) == n:
                    return True
    return False

nice_count = 0
for n in range(2010, 2020):
    if is_nice(n):
        nice_count += 1

print(nice_count)
